    display: flex;
    flex-direction: column;
  }

  .next-action-item {
    display: flex;
    align-items: center;
    gap: var(--space-sm);
    padding-block: var(--space-sm);
    padding-inline: var(--space-sm);
    border-block-end: 1px solid var(--color-border);
  }

  .next-action-item:first-child {
    border-block-start: 1px solid var(--color-border);
  }

  .next-action-item__complete {
    flex-shrink: 0;
  }

  .next-action-item__complete-button {
    background: none;
    border: none;
    padding: var(--space-xs);
    cursor: pointer;
    font-size: var(--font-size-lg);
    line-height: 1;
    color: var(--color-fg-muted);
  }

  .next-action-item__complete-button:hover {
    background: none;
    color: var(--color-primary);
  }

  @media (forced-colors: active) {
    .next-action-item__complete-button {
      border: 1px solid ButtonText;
    }
  }

  .next-action-item__title {
    flex: 1;
    min-inline-size: 0;
    overflow-wrap: break-word;
  }

  .next-action-item__context {
    flex-shrink: 0;
    font-size: var(--font-size-sm);
    color: var(--color-fg-muted);
    padding: var(--space-xs) var(--space-sm);
    background-color: var(--color-gray-100);
    border-radius: var(--radius-full);
  }

  .next-action-item__edit {
    color: var(--color-fg-muted);
    font-size: var(--font-size-sm);
    text-decoration: none;
    flex-shrink: 0;
  }

  .next-action-item__edit:hover {
    color: var(--color-primary);
    text-decoration: underline;
  }

  .next-action-item__delete {
    flex-shrink: 0;
  }

  .next-action-item__delete-button {
    background: none;
    border: none;
    padding: var(--space-xs);
    cursor: pointer;
    color: var(--color-fg-muted);
    font-size: var(--font-size-sm);
    border-radius: var(--radius-sm);
  }

  .next-action-item__delete-button:hover {
    background: none;
    color: var(--color-danger);
  }

  /* Next action edit form */
  .next-action-item__edit-form {
    flex: 1;
    display: flex;
    align-items: center;
    gap: var(--space-xs);
    min-inline-size: 0;
  }

  .next-action-item__edit-input {
    flex: 1;
    min-inline-size: 0;
    font-size: var(--font-size-base);
    padding: var(--space-xs) var(--space-sm);
  }

  .next-action-item__edit-save {
    font-size: var(--font-size-xs);
    padding: var(--space-xs) var(--space-sm);
    border: none;
    border-radius: var(--radius-sm);
    cursor: pointer;
    flex-shrink: 0;
    background-color: var(--color-primary);
    color: white;
  }

  .next-action-item__edit-cancel {
    font-size: var(--font-size-xs);
    color: var(--color-fg-muted);
    text-decoration: none;
    flex-shrink: 0;
  }

  .next-action-item__edit-cancel:hover {
    color: var(--color-fg);
    text-decoration: underline;
  }

  /* Next actions empty state */
  .next-actions__empty-state {
    color: var(--color-fg-muted);
    font-size: var(--font-size-sm);
    text-align: center;
    padding-block: var(--space-xl);
  }
}

/* ==========================================================================
   UTILITIES LAYER
   Helper classes. These have the highest layer priority.
   ========================================================================== */

@layer utilities {
  /* Visually hidden -- accessible to screen readers but not visible.
   * Uses the clip technique for reliable hiding.
   * white-space: nowrap prevents content from being announced as
   * multiple separate items by some screen readers. */
  .visually-hidden,
  .sr-only {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    white-space: nowrap;
    border: 0;
  }

  /* Skip link -- visually hidden until focused, then revealed.
   * Keyboard users tab to this first and see it appear at the
   * top of the page. Uses the base template's skip link:
   * <a href="#main-content" class="skip-link">Skip to main content</a> */
  .skip-link {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    white-space: nowrap;
    border: 0;

    &:focus-visible {
      position: fixed;
      inset-block-start: var(--space-sm);
      inset-inline-start: var(--space-sm);
      z-index: 9999;
      inline-size: auto;
      block-size: auto;
      padding: var(--space-sm) var(--space-md);
      margin: 0;
      overflow: visible;
      clip: auto;
      clip-path: none;
      white-space: normal;
      background-color: var(--color-primary);
      color: white;
      font-size: var(--font-size-sm);
      font-weight: var(--font-medium);
      border-radius: var(--radius-md);
      box-shadow: var(--shadow-md);
    }
  }
}
